import 'package:flutter/material.dart';
class ErrorView extends StatelessWidget{final String message;final VoidCallback? onRetry;const ErrorView({super.key,required this.message,this.onRetry});@override Widget build(BuildContext c)=>Center(child:Padding(padding:const EdgeInsets.all(24),child:Column(mainAxisSize:MainAxisSize.min,children:[const Icon(Icons.error_outline,size:52,color:Colors.redAccent),const SizedBox(height:12),Text(message,textAlign:TextAlign.center),if(onRetry!=null)TextButton(onPressed:onRetry,child:const Text('Try again'))])));}
